 11Ôćĺ
 12Ôćĺexport interface ProductFeatureResponse {
 13Ôćĺ	description?: string[];
 14Ôćĺ	error?: string;
 15Ôćĺ}
 16Ôćĺ
 17Ôćĺexport interface EmbeddingTextResponse {
