 21Ôćĺexport interface ProductEmbeddingInput {
 22Ôćĺ	name: string;
 23Ôćĺ	product_type: string | null;
 24Ôćĺ	style_type: string | null;
 25Ôćĺ	primary_category_name: string | null;
 26Ôćĺ	sub_category_names: string[] | null;
 27Ôćĺ	broad_category_names: string[] | null;
 28Ôćĺ	features: string | null;
 29Ôćĺ	general_comments: string | null;
 30Ôćĺ	decoration_method: string | null;
 31Ôćĺ	manufacturer: string | null;
 32Ôćĺ	brand: string[] | null;
 33Ôćĺ	condensed_features: string[] | null;
 34Ôćĺ	sizes: string[] | null;
 35Ôćĺ}
