 37Ôćĺ@Injectable()
 38Ôćĺexport class OpenAIService {
 39Ôćĺ	private readonly logger = new Logger(OpenAIService.name);
 40Ôćĺ	private readonly openai: OpenAI;
 41Ôćĺ
 42Ôćĺ	constructor() {
 43Ôćĺ		const apiKey = getEnv<string>({ key: OPENAI_API_KEY });
 44Ôćĺ		this.openai = new OpenAI({ apiKey, baseURL: 'https://api.openai.com/v1' });
 45Ôćĺ	}
 46Ôćĺ
 47Ôćĺ	async generateProductFeatures({
 48Ôćĺ		productInfo,
 49Ôćĺ	}: {
 50Ôćĺ		productInfo: MMSStyleToProcess;
 51Ôćĺ	}): Promise<ProductFeatureResponse> {
 52Ôćĺ		try {
 53Ôćĺ			this.logger.log(`Processing product features for id: ${productInfo.id}`);
 54Ôćĺ
 55Ôćĺ			const prompt = this.buildPrompt({ productInfo });
 56Ôćĺ
 57Ôćĺ			const response = await this.getOpenAIResponse(prompt);
 58Ôćĺ
 59Ôćĺ			this.logger.log(`Successfully generated features for id: ${productInfo.id}`);
 60Ôćĺ			return response;
 61Ôćĺ		} catch (error) {
 62Ôćĺ			this.logger.error(`Error processing product ${productInfo.id}:`, error);
 63Ôćĺ			return {
 64Ôćĺ				error: `Failed to process product: ${error instanceof Error ? error.message : 'Unknown error'}`,
 65Ôćĺ			};
 66Ôćĺ		}
 67Ôćĺ	}
 68Ôćĺ
 69Ôćĺ	@LogExecution({
 70Ôćĺ		paramFormatter: (params: [{ product: ProductEmbeddingInput }]) => ({
 71Ôćĺ			name: params[0].product.name,
 72Ôćĺ		}),
 73Ôćĺ	})
 74Ôćĺ	async generateEmbeddingText({
 75Ôćĺ		product,
 76Ôćĺ	}: {
 77Ôćĺ		product: ProductEmbeddingInput;
 78Ôćĺ	}): Promise<EmbeddingTextResponse> {
 79Ôćĺ		const productData = {
 80Ôćĺ			name: product.name,
 81Ôćĺ			product_type: product.product_type,
 82Ôćĺ			style_type: product.style_type,
 83Ôćĺ			category: product.primary_category_name,
 84Ôćĺ			subcategories: product.sub_category_names,
 85Ôćĺ			broad_categories: product.broad_category_names,
 86Ôćĺ			features: product.features,
 87Ôćĺ			description: product.general_comments,
 88Ôćĺ			decoration_method: product.decoration_method,
 89Ôćĺ			manufacturer: product.manufacturer,
 90Ôćĺ			brand: product.brand,
 91Ôćĺ			condensed_features: product.condensed_features,
 92Ôćĺ			sizes: product.sizes,
 93Ôćĺ		};
 94Ôćĺ
 95Ôćĺ		const completion = await this.openai.chat.completions.create({
 96Ôćĺ			messages: [
 97Ôćĺ				{
 98Ôćĺ					role: 'system',
 99Ôćĺ					content: `You are a senior data engineer and data analyst who is an expert in generating text embeddings for neural product search.
100ÔćĺYour task: given product data, produce a single natural-language paragraph optimized for a distilroberta-v1 embedding model (512 token limit).
101Ôćĺ
102ÔćĺRules:
103Ôćĺ- Write fluent, human-readable sentences ÔÇö no bullet points, no pipe delimiters, no markdown.
104Ôćĺ- Lead with the product name and what it is.
105Ôćĺ- Describe key physical features, materials, and use cases.
106Ôćĺ- Mention important category information (primary category, and few broad categories if they exist). as words, not as sentences.
107Ôćĺ- Highlight occasions, events, and audiences this product is ideal for.
108Ôćĺ- Include the decoration/customization method naturally (3-4 words).
109Ôćĺ- Mention the manufacturer/brand only once if relevant.
110Ôćĺ- Highlight occasions, events, and audiences this product is ideal for.
111Ôćĺ- Count a few (6 max) key features and details from condensed_features if available, use 3-4 words per feature, and integrate them naturally into the text.
112Ôćĺ- Skip null/empty fields silently ÔÇö never say "unknown" or "N/A".
113Ôćĺ- Do NOT invent features not present in the input data.
114Ôćĺ- Output ONLY valid JSON: {"text": "your paragraph here"}`,
115Ôćĺ				},
116Ôćĺ				{
117Ôćĺ					role: 'user',
118Ôćĺ					content: `Generate embedding text for this product:\n${JSON.stringify(productData)}`,
119Ôćĺ				},
120Ôćĺ			],
121Ôćĺ			model: 'gpt-4o-mini',
122Ôćĺ			response_format: { type: 'json_object' },
123Ôćĺ			temperature: 0.3,
124Ôćĺ			max_tokens: 350,
125Ôćĺ		});
126Ôćĺ
127Ôćĺ		if (!completion.choices[0]?.message.content) {
128Ôćĺ			throw new Error('Empty response from OpenAI');
129Ôćĺ		}
130Ôćĺ
131Ôćĺ		const parsed = JSON.parse(
132Ôćĺ			completion.choices[0].message.content,
133Ôćĺ		) as EmbeddingTextResponse;
134Ôćĺ
135Ôćĺ		if (!parsed.text || typeof parsed.text !== 'string') {
136Ôćĺ			this.logger.error(
137Ôćĺ				'Invalid response format from OpenAI:',
138Ôćĺ				JSON.stringify(completion.choices[0].message.content),
139Ôćĺ			);
140Ôćĺ			return { text: '' };
141Ôćĺ		}
142Ôćĺ
143Ôćĺ		return parsed;
144Ôćĺ	}
145Ôćĺ
146Ôćĺ	private buildPrompt({ productInfo }: { productInfo: MMSStyleToProcess }): string {
147Ôćĺ		return `
148ÔćĺThe description should be present and be suitable for product recommendation model without mentioning names and brands.
149ÔćĺDescription should be an array of feature strings.
150ÔćĺResponse format: { "description": feature[] } in JSON format.
151Ôćĺ
152ÔćĺProduct in JSON format: ${JSON.stringify(productInfo, null, 2)}
153Ôćĺ`;
154Ôćĺ	}
155Ôćĺ
156Ôćĺ	private async getOpenAIResponse(prompt: string): Promise<ProductFeatureResponse> {
157Ôćĺ		const completion = await this.openai.chat.completions.create({
158Ôćĺ			messages: [
159Ôćĺ				{
160Ôćĺ					role: 'system',
161Ôćĺ					content: `You are an expert in data preprocessing and feature engineering for machine learning.
162Ôćĺ				Your job is prepare data for training Related Products model based on "Content-based" approach.
163Ôćĺ				Your need to define key features, product details and important words for products and build array of features.
164Ôćĺ          `,
165Ôćĺ				},
166Ôćĺ				{ role: 'user', content: [{ type: 'text', text: prompt }] },
167Ôćĺ			],
168Ôćĺ			model: 'gpt-4o-mini',
169Ôćĺ			response_format: { type: 'json_object' },
170Ôćĺ		});
171Ôćĺ
172Ôćĺ		if (!completion.choices[0]) {
173Ôćĺ			return { error: 'No response from OpenAI' };
174Ôćĺ		}
175Ôćĺ
176Ôćĺ		const content = completion.choices[0].message.content;
177Ôćĺ		if (!content) {
178Ôćĺ			return { error: 'Empty response from OpenAI' };
179Ôćĺ		}
180Ôćĺ
181Ôćĺ		try {
182Ôćĺ			const parsedResponse = JSON.parse(content) as ProductFeatureResponse;
183Ôćĺ
184Ôćĺ			const fieldNames = Object.keys(parsedResponse);
185Ôćĺ			const firstFieldName = fieldNames[0] as keyof ProductFeatureResponse;
186Ôćĺ
187Ôćĺ			if (!parsedResponse.description) {
188Ôćĺ				const fieldValue = parsedResponse[firstFieldName];
189Ôćĺ				return {
190Ôćĺ					description:
191Ôćĺ						typeof fieldValue === 'string'
192Ôćĺ							? (JSON.parse(fieldValue) as string[])
193Ôćĺ							: (fieldValue ?? []),
194Ôćĺ					...parsedResponse,
195Ôćĺ				};
196Ôćĺ			}
197Ôćĺ
198Ôćĺ			return parsedResponse;
199Ôćĺ		} catch (parseError) {
200Ôćĺ			this.logger.error('Failed to parse OpenAI response:', parseError);
201Ôćĺ			return { error: 'Failed to parse OpenAI response' };
202Ôćĺ		}
203Ôćĺ	}
204Ôćĺ}
