298Ôćĺ	async searchProducts({
299Ôćĺ		queryText,
300Ôćĺ		size = NEURAL_SEARCH_LIMIT,
301Ôćĺ		tags,
302Ôćĺ	}: {
303Ôćĺ		queryText: string;
304Ôćĺ		size?: number;
305Ôćĺ		tags?: string[];
306Ôćĺ	}): Promise<IOpensearchProduct[]> {
307Ôćĺ		const sanitizedQuery = this.sanitizeQuery({ text: queryText });
308Ôćĺ		const normalizedQuery = this.normalizeQuery({ text: sanitizedQuery });
309Ôćĺ		const genderProductTypes = this.detectGenderProductTypes({ text: sanitizedQuery });
310Ôćĺ		const priceLevels = this.detectPriceLevels({ text: sanitizedQuery });
311Ôćĺ		const brand = this.detectBrand({ text: sanitizedQuery });
312Ôćĺ
313Ôćĺ		const baseFilters: object[] = [{ term: { status: 'active' } }];
314Ôćĺ
315Ôćĺ		if (genderProductTypes) {
316Ôćĺ			baseFilters.push({ terms: { product_type: genderProductTypes } });
317Ôćĺ		}
318Ôćĺ
319Ôćĺ		const priceBoosts: object[] =
320Ôćĺ			priceLevels?.map((level) => ({
321Ôćĺ				term: { price_level: { value: level, boost: 1.5 } },
322Ôćĺ			})) ?? [];
323Ôćĺ
324Ôćĺ		const brandBoosts: object[] = brand ? [{ terms: { brand: [brand], boost: 2 } }] : [];
325Ôćĺ
326Ôćĺ		const categoryBoosts: object[] = tags?.length
327Ôćĺ			? [
328Ôćĺ					{ terms: { primary_category_name: tags } },
329Ôćĺ					{ terms: { broad_category_names: tags } },
330Ôćĺ					{ terms: { sub_category_names: tags } },
331Ôćĺ				]
332Ôćĺ			: [];
333Ôćĺ
334Ôćĺ		const hits = await this.opensearchService.search({
335Ôćĺ			indexName: this.indexName,
336Ôćĺ			searchPipeline: 'hybrid-search-pipeline',
337Ôćĺ			body: {
338Ôćĺ				size,
339Ôćĺ				min_score: 0.4,
340Ôćĺ				query: {
341Ôćĺ					hybrid: {
342Ôćĺ						queries: [
343Ôćĺ							{
344Ôćĺ								bool: {
345Ôćĺ									should: [...priceBoosts, ...brandBoosts, ...categoryBoosts],
346Ôćĺ									filter: baseFilters,
347Ôćĺ								},
348Ôćĺ							},
349Ôćĺ							{
350Ôćĺ								neural: {
351Ôćĺ									product_embedding: {
352Ôćĺ										query_text: normalizedQuery,
353Ôćĺ										model_id: this.getModelId(),
354Ôćĺ										k: size * 5,
355Ôćĺ										filter: { bool: { filter: baseFilters } },
356Ôćĺ									},
357Ôćĺ								},
358Ôćĺ							},
359Ôćĺ						],
360Ôćĺ					},
361Ôćĺ				},
362Ôćĺ				collapse: { field: 'product_id' },
363Ôćĺ				_source: { excludes: ['product_embedding', 'combined_text_for_embedding'] },
364Ôćĺ			},
365Ôćĺ		});
366Ôćĺ
367Ôćĺ		const maxScore = Math.max(...hits.map((hit) => hit._score), 1);
368Ôćĺ
369Ôćĺ		return hits.map((hit) => ({
370Ôćĺ			...(hit._source as IOpensearchProduct),
371Ôćĺ			_id: hit._id,
372Ôćĺ			confidenceScore: Math.round((hit._score / maxScore) * 100),
373Ôćĺ		}));
374Ôćĺ	}
