420Ôćĺ			...(style.brand?.length
421Ôćĺ				? [`Brand: ${this.cleanText({ text: style.brand[0] })}`]
422Ôćĺ				: []),
423Ôćĺ			...(normalizedCondensedFeatures?.length
424Ôćĺ				? [this.cleanText({ text: normalizedCondensedFeatures.join(', ') })]
425Ôćĺ				: []),
426Ôćĺ			...(style.style_type ? [this.cleanText({ text: style.style_type })] : []),
427Ôćĺ			...(style.primary_category_name
