436Ôćĺ					]
437Ôćĺ				: []),
438Ôćĺ			...(style.decoration_method
439Ôćĺ				? [`Decoration: ${this.cleanText({ text: style.decoration_method })}`]
440Ôćĺ				: []),
441Ôćĺ			...(style.features
442Ôćĺ				? [`Features: ${this.cleanText({ text: style.features })}`]
443Ôćĺ				: []),
444Ôćĺ		];
445Ôćĺ
446Ôćĺ		const combinedText = parts.filter(Boolean).join('. ');
447Ôćĺ
448Ôćĺ		this.logger.debug(
449Ôćĺ			`Combined text length for style_id ${style.style_id}: ${combinedText.length} characters`,
450Ôćĺ		);
451Ôćĺ
452Ôćĺ		return combinedText;
453Ôćĺ	}
