100Ôćĺ	@LogExecution({ logParams: false, logResponse: false })
101Ôćĺ	async bulkIndex({
102Ôćĺ		indexName,
103Ôćĺ		documents,
104Ôćĺ	}: {
105Ôćĺ		indexName: string;
106Ôćĺ		documents: { _id: string; [key: string]: unknown }[];
107Ôćĺ	}): Promise<{ indexed: number; errors: number }> {
108Ôćĺ		try {
109Ôćĺ			if (documents.length === 0) {
110Ôćĺ				return { indexed: 0, errors: 0 };
111Ôćĺ			}
112Ôćĺ
113Ôćĺ			const body = documents.flatMap((doc) => {
114Ôćĺ				const { _id, ...docWithoutId } = doc;
115Ôćĺ				return [{ index: { _index: indexName, _id } }, docWithoutId];
116Ôćĺ			});
117Ôćĺ
118Ôćĺ			const response = await this.client.bulk({ body });
119Ôćĺ
120Ôćĺ			const errorItems = response.body.items.filter(
121Ôćĺ				(item: { index?: { error?: unknown } }) => item.index?.error,
122Ôćĺ			);
123Ôćĺ
124Ôćĺ			const errors = errorItems.length;
125Ôćĺ			const indexed = documents.length - errors;
126Ôćĺ
127Ôćĺ			if (errors > 0) {
128Ôćĺ				this.logger.warn(
129Ôćĺ					`Bulk index completed with ${errors} errors out of ${documents.length} documents`,
130Ôćĺ				);
131Ôćĺ
132Ôćĺ				const sampleErrors = errorItems
133Ôćĺ					.slice(0, 3)
134Ôćĺ					.map((item: { index?: { error?: { type?: string; reason?: string } } }) => ({
135Ôćĺ						type: item.index?.error?.type,
136Ôćĺ						reason: item.index?.error?.reason,
137Ôćĺ					}));
138Ôćĺ
139Ôćĺ				this.logger.error(`Sample errors: ${JSON.stringify(sampleErrors, null, 2)}`);
140Ôćĺ			}
141Ôćĺ
142Ôćĺ			return { indexed, errors };
143Ôćĺ		} catch (error: unknown) {
144Ôćĺ			this.handleError({ context: 'Bulk index failed', error });
145Ôćĺ			throw error;
146Ôćĺ		}
147Ôćĺ	}
