271Ôćĺ		intervalMs?: number;
272Ôćĺ		maxAttempts?: number;
273Ôćĺ	}): Promise<{ state: string; model_id?: string }> {
274Ôćĺ		for (let attempt = 1; attempt <= maxAttempts; attempt++) {
275Ôćĺ			const task = await this.getTask({ taskId });
276Ôćĺ			this.logger.log(
277Ôćĺ				`Task ${taskId} ÔÇö attempt ${attempt}/${maxAttempts}, state: ${task.state}`,
278Ôćĺ			);
279Ôćĺ
280Ôćĺ			if (task.state === 'COMPLETED') {
281Ôćĺ				return task;
282Ôćĺ			}
283Ôćĺ
284Ôćĺ			if (task.state === 'FAILED') {
285Ôćĺ				throw new Error(`Task ${taskId} failed`);
286Ôćĺ			}
287Ôćĺ
288Ôćĺ			await new Promise((resolve) => setTimeout(resolve, intervalMs));
289Ôćĺ		}
290Ôćĺ
291Ôćĺ		throw new Error(`Task ${taskId} timed out after ${maxAttempts} attempts`);
292Ôćĺ	}
